import urllib.parse, urllib.request

base='http://localhost:80/'
endpoints=['index.php','about.php','contact.php','post.php']
params=['file','page','path','template','view','inc','include','lang','p','name','module','dir','folder','load','url','content','component','post']
values=['posts/ScriptKiddie.php','../posts/ScriptKiddie.php','./posts/ScriptKiddie.php','posts/../posts/ScriptKiddie.php']
